import{_ as a,o as i,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"69. Breast Feeding Facilities","description":"","frontmatter":{"title":"69. Breast Feeding Facilities","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","breaks","flexible-work"]},"headers":[],"relativePath":"ebas/mspp/leave/69-breast-feeding-facilities.md","filePath":"ebas/mspp/leave/69-breast-feeding-facilities.md"}'),s={name:"ebas/mspp/leave/69-breast-feeding-facilities.md"};function o(l,e,n,p,c,d){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_69-breast-feeding-facilities" tabindex="-1">69. Breast Feeding Facilities <a class="header-anchor" href="#_69-breast-feeding-facilities" aria-label="Permalink to &quot;69. Breast Feeding Facilities&quot;">​</a></h1><p><strong>69.1</strong> Paid break Each Employer will provide reasonable paid break time for an Employee to express breast milk for their nursing child each time such Employee has need to express the milk, or breastfeed the child within the workplace, for one year after the child’s birth.</p><p><strong>69.2</strong> Place to express or feed The Employer will provide a comfortable place, other than a bathroom, that is shielded from view and free from intrusion from co-workers and the public, which may be used by an Employee to express milk or breastfeed a child in privacy.</p><p><strong>69.3</strong> Storage</p><p><strong>a.</strong> Appropriate refrigeration will be available in proximity to the area for breast milk storage.</p><p><strong>b.</strong> Responsibility for labelling, storage and use is with the Employee.</p><p>Plain language terms: lactation, pumping, expressing milk.</p>',7)])])}const f=a(s,[["render",o]]);export{m as __pageData,f as default};
